import React from 'react';
import { AnalysisResult, ModelMetrics, AttackStatistics } from '../types';

interface AnalysisResultsProps {
    analysisResult?: AnalysisResult;
    metrics?: ModelMetrics;
    statistics?: AttackStatistics;
}

const AnalysisResults: React.FC<AnalysisResultsProps> = ({ analysisResult, metrics, statistics }) => {
    if (!analysisResult && !metrics && !statistics) {
        return <div><p>No analysis results available. Please upload and analyze a dataset first.</p></div>;
    }

    return (
        <div style={{ padding: '20px', border: '1px solid #ddd', borderRadius: '8px' }}>
            <h2>Analysis Results</h2>

            {analysisResult && (
                <div style={{ marginBottom: '20px' }}>
                    <h3>Prediction Summary</h3>
                    <p><strong>Total Records:</strong> {analysisResult.total_records}</p>
                    <p><strong>Attacks Detected:</strong> {analysisResult.attacks_detected}</p>
                    <p><strong>Normal Records:</strong> {analysisResult.normal_records}</p>
                    <p><strong>Attack Percentage:</strong> {analysisResult.attack_percentage}%</p>
                </div>
            )}

            {metrics && (
                <div style={{ marginBottom: '20px' }}>
                    <h3>Model Metrics</h3>
                    <p><strong>Accuracy:</strong> {(metrics.accuracy * 100).toFixed(2)}%</p>
                    <p><strong>Precision:</strong> {(metrics.precision * 100).toFixed(2)}%</p>
                    <p><strong>Recall:</strong> {(metrics.recall * 100).toFixed(2)}%</p>
                    <p><strong>F1 Score:</strong> {(metrics.f1_score * 100).toFixed(2)}%</p>
                </div>
            )}

            {statistics && (
                <div style={{ marginBottom: '20px' }}>
                    <h3>Attack Statistics</h3>
                    <p><strong>Detection Rate:</strong> {statistics.detection_rate}%</p>
                    <h4>Attack Types Detected:</h4>
                    {Object.keys(statistics.attack_types).length > 0 ? (
                        <ul>
                            {Object.entries(statistics.attack_types).map(([type, count]) => (
                                <li key={type}>{type}: {count}</li>
                            ))}
                        </ul>
                    ) : (
                        <p>No specific attack types detected.</p>
                    )}
                </div>
            )}
        </div>
    );
};

export default AnalysisResults;
